# GMC710 IAS Speed UP Wheel Direction
# 3PFD_8 = "1 (>B:AUTOPILOT_VerticalSpeed_Dec)"
PFD_38 = "(A:AUTOPILOT FLIGHT LEVEL CHANGE, Bool) if{ (>K:AP_SPD_VAR_INC) } els{ (A:AUTOPILOT VERTICAL HOLD, Bool) if{ (>K:AP_VS_VAR_INC) } els{ (>K:AP_PITCH_REF_INC_UP) } }"
PFD_38_L = "(A:AUTOPILOT FLIGHT LEVEL CHANGE, Bool) if{ (>K:AP_SPD_VAR_INC) (>K:AP_SPD_VAR_INC) (>K:AP_SPD_VAR_INC) (>K:AP_SPD_VAR_INC) (>K:AP_SPD_VAR_INC) } els{ (A:AUTOPILOT VERTICAL HOLD, Bool) if{ (>K:AP_VS_VAR_INC) (>K:AP_VS_VAR_INC) (>K:AP_VS_VAR_INC) (>K:AP_VS_VAR_INC) (>K:AP_VS_VAR_INC) } els{ (>K:AP_PITCH_REF_INC_UP) (>K:AP_PITCH_REF_INC_UP) (>K:AP_PITCH_REF_INC_UP) (>K:AP_PITCH_REF_INC_UP) (>K:AP_PITCH_REF_INC_UP) } }"
PFD_39 = unassigned

# GMC710 IAS Speed DN Wheel Direction
# PFD_3E = "1 (>B:AUTOPILOT_VerticalSpeed_Inc)"
PFD_3E = "(A:AUTOPILOT FLIGHT LEVEL CHANGE, Bool) if{ (>K:AP_SPD_VAR_DEC) } els{ (A:AUTOPILOT VERTICAL HOLD, Bool) if{ (>K:AP_VS_VAR_DEC) } els{ (>K:AP_PITCH_REF_INC_DN) } }"
